/**
 * @param {number[]} nums
 * @param {number[][]} queries
 * @return {number[]}
 */
function solve(nums, queries) {
    const results = [];

    for (const query of queries) {
        const [l, r, k] = query;

        // 1. Identify all positive even numbers present in nums[l..r]
        // Since nums is strictly increasing, we can iterate or use properties.
        // We only care about the values, not their original positions.
        const removedEvens = new Set();
        for (let i = l; i <= r; i++) {
            const val = nums[i];
            if (val % 2 === 0) {
                removedEvens.add(val);
            }
        }

        // 2. We are looking for the k-th smallest positive even number NOT in removedEvens.
        // The sequence of all positive even numbers is 2, 4, 6, 8, 10, ...
        // The i-th smallest positive even number is 2 * i.

        // We can use binary search on the answer (the desired even number 'X').
        // Let's assume the answer is X = 2 * N. We want to find the smallest N such that 
        // the count of remaining even numbers less than or equal to X is at least k.

        // Count of even numbers <= X: N (since X = 2*N)
        // Count of removed even numbers <= X: |{e in removedEvens | e <= X}|
        // Count of remaining even numbers <= X: N - |{e in removedEvens | e <= X}|

        // We want to find the smallest X such that:
        // (X / 2) - |{e in removedEvens | e <= X}| >= k

        // The maximum possible answer X can be estimated.
        // If k is large (up to 10^9), X could be around 2 * 10^9 + |removedEvens|.
        // Since |removedEvens| <= nums.length <= 10^5, X max is around 2 * 10^9 + 10^5.

        // Search range for N = X/2:
        // Lower bound for N: 1 (since k >= 1)
        // Upper bound for N: k + |removedEvens| (A safe upper bound, since if we take the first k+R evens, 
        // at most R are removed, so at least k remain). Since k <= 10^9 and R <= 10^5, 2*10^9 is safe.
        let lowN = 1;
        // A generous upper bound for N: 2 * 10^9 + 10^5 + 1
        let highN = 2 * 10**9 + 100005; 
        let ansN = highN;

        // Pre-sort removedEvens to speed up counting inside binary search
        const sortedRemovedEvens = Array.from(removedEvens).sort((a, b) => a - b);

        while (lowN <= highN) {
            const midN = Math.floor((lowN + highN) / 2);
            const X = 2 * midN;

            // Count how many elements in sortedRemovedEvens are <= X
            // We use upper_bound logic on sortedRemovedEvens.
            let removedCount = 0;

            // Since sortedRemovedEvens is small (<= 10^5), linear scan is fast enough, 
            // but we can use binary search (or a simple loop since we are inside a BS)
            // to find the count efficiently.

            // Count <= X: Find the index of the first element > X. That index is the count.
            let count = 0;
            for (const removedVal of sortedRemovedEvens) {
                if (removedVal <= X) {
                    count++;
                } else {
                    break;
                }
            }

            // Remaining count <= X: midN (total evens <= X) - count (removed evens <= X)
            const remainingCount = midN - count;

            if (remainingCount >= k) {
                // midN is a possible answer for N. Try smaller N.
                ansN = midN;
                highN = midN - 1;
            } else {
                // Not enough remaining elements. Need a larger N.
                lowN = midN + 1;
            }
        }

        results.push(2 * ansN);
    }

    return results;
}

